// ============================================================================
// Main Entry Point
// ============================================================================

int main(int argc, char** argv) {
    // Parse command line for filter
    const char* filter = nullptr;
    for (int i = 1; i < argc; i++) {
        if (strncmp(argv[i], "--filter=", 9) == 0) {
            filter = argv[i] + 9;
        } else if (strcmp(argv[i], "--help") == 0 || strcmp(argv[i], "-h") == 0) {
            printf("Usage: GitSmarterTest.exe [options]\n");
            printf("Options:\n");
            printf("  --filter=<pattern>  Run only tests containing <pattern>\n");
            printf("  --help, -h          Show this help\n");
            return 0;
        }
    }

    // Load fixture SHAs before running tests
    if (!fixture_shas_load(L"test\\fixtures\\test_repo")) {
        printf("Warning: Could not load fixture SHAs. Some tests may fail.\n");
    }

    // Run tests
    return Test::run_all_tests(filter);
}
